SET TOTAL = #{total},
    HIT_CNT1 = #{hitCnt1},
    HIT_CNT2 = #{hitCnt2},
    HIT_CNT3 = #{hitCnt3},
    HIT_CNT4 = #{hitCnt4},
    ARIN_USE_CNT = #{arinUseCnt},
    TOTAL_OUTPUT_CNT = #{totalOutputCnt}
WHERE TYPE = #{type}
  AND RSRE_YMD = #{rsreYmd}
  AND HDQR_BOB_DCD = #{hdqrBobDcd}

